INSERT INTO "UI_DataItems" VALUES(1,2,'account_id','Account','Unique identifier of the account.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2,2,'account_category_code','Category','Select a category to indicate whether the customer account is standard or preferred. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(3,2,'customer_size_code','Customer Size','Select the size category or range of the account for segmentation and reporting purposes. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(4,2,'preferred_contact_method_code','Preferred Method of Contact','Select the preferred method of contact. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(5,2,'customer_type_code','Relationship Type','Select the category that best describes the relationship between the account and your organization. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(6,2,'account_rating_code','Account Rating','Select a rating to indicate the value of the customer account. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(7,2,'industry_code','Industry','Select the account''s primary industry for use in marketing segmentation and demographic analysis. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(8,2,'territory_code','Territory Code','Select a region or territory for the account for use in segmentation and analysis. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(9,2,'account_classification_code','Classification','Select a classification code to indicate the potential value of the customer account based on the projected return on investment, cooperation level, sales cycle length or other criteria. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(10,2,'business_type_code','Business Type','Select the legal designation or other business type of the account for contracts or reporting purposes. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(11,2,'traversed_path','Traversed Path','For internal use only.','VARCHAR',1250,5000,NULL,0,1,NULL,NULL,'maxlength: 1250','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(12,2,'payment_terms_code','Payment Terms','Select the payment terms to indicate when the customer needs to pay the total amount. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(13,2,'shipping_method_code','Shipping Method','Select a shipping method for deliveries sent to the account''s address to designate the preferred carrier or other delivery option. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(14,2,'participates_in_workflow','Participates in Workflow','For system use only. Legacy Microsoft Dynamics CRM 3.0 workflow data.','BOOLEAN',5,20,NULL,0,1,NULL,NULL,'^(true|false|0|1)$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(15,2,'name','Account Name','Type the company or business name.','VARCHAR',160,640,NULL,0,1,NULL,NULL,'maxlength: 160','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(16,2,'account_number','Account Number','Type an ID number or code for the account to quickly search and identify the account in system views.','VARCHAR',20,80,NULL,0,1,NULL,NULL,'maxlength: 20','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(17,2,'revenue','Annual Revenue','Type the annual revenue for the account, used as an indicator in financial performance analysis.','DECIMAL',19,76,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(18,2,'number_of_employees','Number of Employees','Type the number of employees that work at the account for use in marketing segmentation and demographic analysis.','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(19,2,'description','Description','Type additional information to describe the account, such as an excerpt from the company''s website.','VARCHAR',2000,8000,NULL,0,1,NULL,NULL,'maxlength: 2000','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(20,2,'sic','SIC Code','Type the Standard Industrial Classification (SIC) code that indicates the account''s primary industry of business, for use in marketing segmentation and demographic analysis.','VARCHAR',20,80,NULL,0,1,NULL,NULL,'maxlength: 20','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(21,2,'ownership_code','Ownership','Select the account''s ownership structure, such as public or private. Option-set (enumerated integer codes).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(22,2,'market_cap','Market Capitalization','Type the market capitalization of the account to identify the company''s equity, used as an indicator in financial performance analysis.','DECIMAL',19,76,NULL,0,1,NULL,NULL,'^-?\d+$','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
