INSERT INTO "UI_DataItems" VALUES(24,2,'ticker_symbol','Ticker Symbol','Type the stock exchange symbol for the account to track financial performance of the company. You can click the code entered in this field to access the latest trading information from MSN Money.','VARCHAR',10,40,NULL,0,1,NULL,NULL,'maxlength: 10','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
