INSERT INTO "UI_DataItems" VALUES(26,2,'web_site_url','Website','Type the account''s website URL to get quick details about the company profile.','VARCHAR',200,800,NULL,0,1,NULL,NULL,'maxlength: 200','CDM schemaDocuments (master)','2026-06-28 06:03:06','2026-06-28 06:03:06');
