INSERT INTO "UI_DataItems" VALUES(1147,26,'sscc','SSCC','GS1 Application Identifier (00) - SSCC. GS1 format: N18,csum,gcppos2.','VARCHAR',18,72,NULL,0,1,NULL,NULL,'N18,csum,gcppos2','GS1 Barcode Syntax Dictionary','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1148,77,'gtin','GTIN','A Global Trade Item Number ([GTIN](https://www.gs1.org/standards/id-keys/gtin)). GTINs identify trade items, including products and services, using numeric identification codes. A correct [[gtin]] value should be a valid GTIN, which means that it should be an all-numeric string of either 8, 12, 13 or 14 digits, or a "GS1 Digital Link" URL based on such a string. The numeric component should also have a [valid GS1 check digit](https://www.gs1.org/services/check-digit-calculator) and meet the other rules for valid GTINs. See also [GS1''s GTIN Summary](http://www.gs1.org/barcodes/technical/idkeys/gtin) and [Wikipedia](https://en.wikipedia.org/wiki/Global_Trade_Item_Number) for more details. Left-padding of the gtin values is not required or encouraged. The [[gtin]] property generalizes the earlier [[gtin8]], [[gtin12]], [[gtin13]], and [[gtin14]] properties. The GS1 [digital link specifications](https://www.gs1.org/standards/Digital-Link/) expresses GTINs as URLs (URIs, IRIs, etc.). Digital Links should be populated into the [[hasGS1DigitalLink]] attribute. Note also that this is a definition for how to include GTINs in Schema.org data, and not a definition of GTINs in general - see the GS1 documentation for authoritative details.','VARCHAR',14,56,NULL,0,1,NULL,NULL,'N14,csum,gcppos2','GS1 Barcode Syntax Dictionary; schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
