INSERT INTO "UI_DataItems" VALUES(1628,113,'use_create_lots','Create New Lots/Serial Numbers','If this is checked only, it will suppose you want to create new Lots/Serial Numbers, so you can provide them in a text field. ','BOOLEAN',5,20,NULL,0,1,NULL,NULL,'^(true|false|0|1)$','Odoo 17.0','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1629,113,'use_existing_lots','Use Existing Lots/Serial Numbers','If this is checked, you will be able to choose the Lots/Serial Numbers. You can also decide to not put lots in this operation type.  This means it will create stock with no lot or not put a restriction on the lot taken. ','BOOLEAN',5,20,NULL,0,1,NULL,NULL,'^(true|false|0|1)$','Odoo 17.0','2026-06-28 06:03:06','2026-06-28 06:03:06');
