INSERT INTO "UI_DataItems" VALUES(1765,22,'balance','balance','The current balance, if any, that''s stored on the customer in their default currency. If negative, the customer has credit to apply to their next invoice. If positive, the customer has an amount owed that''s added to their next invoice. The balance only considers amounts that Stripe hasn''t successfully applied to any invoice. It doesn''t reflect unpaid invoices. This balance is only taken into account after invoices finalize. For multi-currency balances, see [invoice_credit_balance](https://docs.stripe.com/api/customers/object#customer_object-invoice_credit_balance).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1766,22,'business_name','business_name','The customer''s business name.','VARCHAR',150,600,NULL,0,1,NULL,NULL,'maxlength: 150','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1767,22,'cash_balance','cash_balance','The current funds being held by Stripe on behalf of the customer. You can apply these funds towards payment intents when the source is "cash_balance". The `settings[reconciliation_mode]` field describes if these funds apply to these payment intents manually or automatically.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
