INSERT INTO "UI_DataItems" VALUES(1771,22,'default_source','default_source','ID of the default payment source for the customer.
INSERT INTO "UI_DataItems" VALUES(1772,22,'delinquent','delinquent','Tracks the most recent state change on any invoice belonging to the customer. Paying an invoice or marking it uncollectible via the API will set this field to false. An automatic payment failure or passing the `invoice.due_date` will set this field to `true`.
