INSERT INTO "UI_DataItems" VALUES(1778,22,'invoice_credit_balance','invoice_credit_balance','The current multi-currency balances, if any, that''s stored on the customer. If positive in a currency, the customer has a credit to apply to their next invoice denominated in that currency. If negative, the customer has an amount owed that''s added to their next invoice denominated in that currency. These balances don''t apply to unpaid invoices. They solely track amounts that Stripe hasn''t successfully applied to any invoice. Stripe only applies a balance in a specific currency to an invoice after that invoice (which is in the same currency) finalizes.','OBJECT',4000,16000,NULL,0,1,NULL,NULL,'maxlength: 4000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
