INSERT INTO "UI_DataItems" VALUES(1792,22,'tax_exempt','tax_exempt','Describes the customer''s tax exemption status, which is `none`, `exempt`, or `reverse`. When set to `reverse`, invoice and receipt PDFs include the following text: **"Reverse charge"**.','VARCHAR',255,1020,NULL,0,1,NULL,'["exempt", "none", "reverse"]','one of: exempt|none|reverse','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
