INSERT INTO "UI_DataItems" VALUES(1812,75,'billing_scheme','billing_scheme','Describes how to compute the price per period. Either `per_unit` or `tiered`. `per_unit` indicates that the fixed amount (specified in `unit_amount` or `unit_amount_decimal`) will be charged per unit in `quantity` (for prices with `usage_type=licensed`), or per unit of total usage (for prices with `usage_type=metered`). `tiered` indicates that the unit pricing will be computed using a tiering strategy as defined using the `tiers` and `tiers_mode` attributes.','VARCHAR',255,1020,NULL,1,0,NULL,'["per_unit", "tiered"]','one of: per_unit|tiered','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
