INSERT INTO "UI_DataItems" VALUES(1814,75,'currency','currency','Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).','VARCHAR',255,1020,NULL,1,0,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1815,75,'currency_options','currency_options','Prices defined in each available currency option. Each key must be a three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html) and a [supported currency](https://stripe.com/docs/currencies).','OBJECT',4000,16000,NULL,0,1,NULL,NULL,'maxlength: 4000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1816,75,'custom_unit_amount','custom_unit_amount','When set, provides configuration for the amount to be adjusted by the customer during Checkout Sessions and Payment Links.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1817,75,'id','id','Unique identifier for the object.','VARCHAR',5000,20000,NULL,1,0,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1818,75,'livemode','livemode','If the object exists in live mode, the value is `true`. If the object exists in test mode, the value is `false`.','BOOLEAN',5,20,NULL,1,0,NULL,NULL,'^(true|false|0|1)$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1819,75,'lookup_key','lookup_key','A lookup key used to retrieve prices dynamically from a static string. This may be up to 200 characters.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1820,75,'metadata','metadata','Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format.','OBJECT',4000,16000,NULL,1,0,NULL,NULL,'maxlength: 4000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1821,75,'nickname','nickname','A brief description of the price, hidden from customers.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1822,75,'object','object','String representing the object''s type. Objects of the same type share the same value.','VARCHAR',255,1020,NULL,1,0,NULL,'["price"]','one of: price','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1823,75,'product','product','The ID of the product this price is associated with.','VARCHAR',255,1020,NULL,1,0,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1824,75,'recurring','recurring','The recurring components of a price such as `interval` and `usage_type`.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1825,75,'tax_behavior','tax_behavior','Only required if a [default tax behavior](https://docs.stripe.com/tax/products-prices-tax-categories-tax-behavior#setting-a-default-tax-behavior-(recommended)) was not provided in the Stripe Tax settings. Specifies whether the price is considered inclusive of taxes or exclusive of taxes. One of `inclusive`, `exclusive`, or `unspecified`. Once specified as either `inclusive` or `exclusive`, it cannot be changed.','VARCHAR',255,1020,NULL,0,1,NULL,'["exclusive", "inclusive", "unspecified"]','one of: exclusive|inclusive|unspecified','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1826,75,'tiers','tiers','Each element represents a pricing tier. This parameter requires `billing_scheme` to be set to `tiered`. See also the documentation for `billing_scheme`.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1827,75,'tiers_mode','tiers_mode','Defines if the tiering price should be `graduated` or `volume` based. In `volume`-based tiering, the maximum quantity within a period determines the per unit price. In `graduated` tiering, pricing can change as the quantity grows.','VARCHAR',255,1020,NULL,0,1,NULL,'["graduated", "volume"]','one of: graduated|volume','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1828,75,'transform_quantity','transform_quantity','Apply a transformation to the reported usage or set quantity before computing the amount billed. Cannot be combined with `tiers`.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1829,75,'type','type','One of `one_time` or `recurring` depending on whether the price is for a one-time purchase or a recurring (subscription) purchase.','VARCHAR',255,1020,NULL,1,0,NULL,'["one_time", "recurring"]','one of: one_time|recurring','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1830,75,'unit_amount','unit_amount','The unit amount in cents (or local equivalent) to be charged, represented as a whole integer if possible. Only set if `billing_scheme=per_unit`.','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1831,75,'unit_amount_decimal','unit_amount_decimal','The unit amount in cents (or local equivalent) to be charged, represented as a decimal string with at most 12 decimal places. Only set if `billing_scheme=per_unit`.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1832,30,'account_country','account_country','The country of the business associated with this invoice, most often the business creating the invoice.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1833,30,'account_name','account_name','The public name of the business associated with this invoice, most often the business creating the invoice.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1834,30,'account_tax_ids','account_tax_ids','The account tax IDs associated with the invoice. Only editable when the invoice is a draft.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1835,30,'amount_due','amount_due','Final amount due at this time for this invoice. If the invoice''s total is smaller than the minimum charge amount, for example, or if there is account credit that can be applied to the invoice, the `amount_due` may be 0. If there is a positive `starting_balance` for the invoice (the customer owes money), the `amount_due` will also take that into account. The charge that gets generated for the invoice will be for the amount specified in `amount_due`.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1836,30,'amount_overpaid','amount_overpaid','Amount that was overpaid on the invoice. The amount overpaid is credited to the customer''s credit balance.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1837,30,'amount_paid','amount_paid','The amount, in cents (or local equivalent), that was paid.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1838,30,'amount_paid_off_stripe','amount_paid_off_stripe','Amount, in cents (or local equivalent), that was paid on the invoice outside of Stripe.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1839,30,'amount_remaining','amount_remaining','The difference between amount_due and amount_paid, in cents (or local equivalent).','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1840,30,'amount_shipping','amount_shipping','This is the sum of all the shipping amounts.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1841,30,'application','application','ID of the Connect Application that created the invoice.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1842,30,'attempt_count','attempt_count','Number of payment attempts made for this invoice, from the perspective of the payment retry schedule. Any payment attempt counts as the first attempt, and subsequently only automatic retries increment the attempt count. In other words, manual payment attempts after the first attempt do not affect the retry schedule. If a failure is returned with a non-retryable return code, the invoice can no longer be retried unless a new payment method is obtained. Retries will continue to be scheduled, and attempt_count will continue to increment, but retries will only be executed if a new payment method is obtained.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1843,30,'attempted','attempted','Whether an attempt has been made to pay the invoice. An invoice is not attempted until 1 hour after the `invoice.created` webhook, for example, so you might not want to display that invoice as unpaid to your users.','BOOLEAN',5,20,NULL,1,0,NULL,NULL,'^(true|false|0|1)$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1844,30,'auto_advance','auto_advance','Controls whether Stripe performs [automatic collection](https://docs.stripe.com/invoicing/integration/automatic-advancement-collection) of the invoice. If `false`, the invoice''s state doesn''t automatically advance without an explicit action.','BOOLEAN',5,20,NULL,1,0,NULL,NULL,'^(true|false|0|1)$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1845,30,'automatic_tax','automatic_tax','Automatic tax (Stripe Tax) status for the invoice — whether tax was calculated automatically and the outcome of that calculation.','RELATION',64,256,NULL,1,0,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1846,30,'automatically_finalizes_at','automatically_finalizes_at','The time when this invoice is currently scheduled to be automatically finalized. The field will be `null` if the invoice is not scheduled to finalize in the future. If the invoice is not in the draft state, this field will always be `null` - see `finalized_at` for the time when an already-finalized invoice was finalized.','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1847,30,'billing_reason','billing_reason','Indicates the reason why the invoice was created.
INSERT INTO "UI_DataItems" VALUES(1848,30,'collection_method','collection_method','Either `charge_automatically`, or `send_invoice`. When charging automatically, Stripe will attempt to pay this invoice using the default source attached to the customer. When sending an invoice, Stripe will email this invoice to the customer with payment instructions.','VARCHAR',255,1020,NULL,1,0,NULL,'["charge_automatically", "send_invoice"]','one of: charge_automatically|send_invoice','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1849,30,'confirmation_secret','confirmation_secret','The confirmation secret associated with this invoice. Currently, this contains the client_secret of the PaymentIntent that Stripe creates during invoice finalization.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1850,30,'created','created','Time at which the object was created. Measured in seconds since the Unix epoch.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1851,30,'currency','currency','Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).','VARCHAR',255,1020,NULL,1,0,NULL,NULL,'maxlength: 255','stripe/openapi spec3; Tryton main','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1852,30,'custom_fields','custom_fields','Custom fields displayed on the invoice.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1853,30,'customer','customer','Party placing the order or paying the invoice. (references Organization, Person)','VARCHAR',255,1020,NULL,1,0,NULL,NULL,'maxlength: 255','stripe/openapi spec3; schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1854,30,'customer_account','customer_account','The ID of the account representing the customer to bill.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1855,30,'customer_address','customer_address','The customer''s address. Until the invoice is finalized, this field will equal `customer.address`. Once the invoice is finalized, this field will no longer be updated.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1856,30,'customer_email','customer_email','The customer''s email. Until the invoice is finalized, this field will equal `customer.email`. Once the invoice is finalized, this field will no longer be updated.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1857,30,'customer_name','customer_name','The customer''s name. Until the invoice is finalized, this field will equal `customer.name`. Once the invoice is finalized, this field will no longer be updated.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1858,30,'customer_phone','customer_phone','The customer''s phone number. Until the invoice is finalized, this field will equal `customer.phone`. Once the invoice is finalized, this field will no longer be updated.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1859,30,'customer_shipping','customer_shipping','The customer''s shipping information. Until the invoice is finalized, this field will equal `customer.shipping`. Once the invoice is finalized, this field will no longer be updated.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1860,30,'customer_tax_exempt','customer_tax_exempt','The customer''s tax exempt status. Until the invoice is finalized, this field will equal `customer.tax_exempt`. Once the invoice is finalized, this field will no longer be updated.','VARCHAR',255,1020,NULL,0,1,NULL,'["exempt", "none", "reverse"]','one of: exempt|none|reverse','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1861,30,'customer_tax_ids','customer_tax_ids','The customer''s tax IDs. Until the invoice is finalized, this field will contain the same tax IDs as `customer.tax_ids`. Once the invoice is finalized, this field will no longer be updated.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1862,30,'default_payment_method','default_payment_method','ID of the default payment method for the invoice. It must belong to the customer associated with the invoice. If not set, defaults to the subscription''s default payment method, if any, or to the default payment method in the customer''s invoice settings.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1863,30,'default_source','default_source','ID of the default payment source for the invoice. It must belong to the customer associated with the invoice and be in a chargeable state. If not set, defaults to the subscription''s default source, if any, or to the customer''s default source.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1864,30,'default_tax_rates','default_tax_rates','The tax rates applied to this invoice, if any.','RELATION',64,256,NULL,1,0,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1865,30,'discounts','discounts','The discounts applied to the invoice. Line item discounts are applied before invoice discounts. Use `expand[]=discounts` to expand each discount.','RELATION',64,256,NULL,1,0,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1866,30,'effective_at','effective_at','The date when this invoice is in effect. Same as `finalized_at` unless overwritten. When defined, this value replaces the system-generated ''Date of issue'' printed on the invoice PDF and receipt.','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1867,30,'ending_balance','ending_balance','Ending customer balance after the invoice is finalized. Invoices are finalized approximately an hour after successful webhook delivery or when payment collection is attempted for the invoice. If the invoice has not been finalized yet, this will be null.','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1868,30,'footer','footer','Footer displayed on the invoice.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1869,30,'from_invoice','from_invoice','Details of the invoice that was cloned. See the [revision documentation](https://docs.stripe.com/invoicing/invoice-revisions) for more details.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1870,30,'hosted_invoice_url','hosted_invoice_url','The URL for the hosted invoice page, which allows customers to view and pay an invoice. If the invoice has not been finalized yet, this will be null.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1871,30,'id','id','Unique identifier for the object. For preview invoices created using the [create preview](https://stripe.com/docs/api/invoices/create_preview) endpoint, this id will be prefixed with `upcoming_in`.','VARCHAR',5000,20000,NULL,1,0,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1872,30,'invoice_pdf','invoice_pdf','The link to download the PDF for the invoice. If the invoice has not been finalized yet, this will be null.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1873,30,'last_finalization_error','last_finalization_error','The error encountered during the previous attempt to finalize the invoice. This field is cleared when the invoice is successfully finalized.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1874,30,'latest_revision','latest_revision','The ID of the most recent non-draft revision of this invoice','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1875,30,'lines','lines','The individual line items that make up the invoice. `lines` is sorted as follows: (1) pending invoice items (including prorations) in reverse chronological order, (2) subscription items in reverse chronological order, and (3) invoice items added after invoice creation in chronological order.','OBJECT',4000,16000,NULL,1,0,NULL,NULL,'maxlength: 4000','stripe/openapi spec3; Tryton main','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1876,30,'livemode','livemode','If the object exists in live mode, the value is `true`. If the object exists in test mode, the value is `false`.','BOOLEAN',5,20,NULL,1,0,NULL,NULL,'^(true|false|0|1)$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1877,30,'metadata','metadata','Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format.','OBJECT',4000,16000,NULL,0,1,NULL,NULL,'maxlength: 4000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1878,30,'next_payment_attempt','next_payment_attempt','The time at which payment will next be attempted. This value will be `null` for invoices where `collection_method=send_invoice`.','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1879,30,'number','number','A unique, identifying string that appears on emails sent to the customer for this invoice. This starts with the customer''s unique invoice_prefix if it is specified.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3; Tryton main','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1880,30,'object','object','String representing the object''s type. Objects of the same type share the same value.','VARCHAR',255,1020,NULL,1,0,NULL,'["invoice"]','one of: invoice','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1881,30,'on_behalf_of','on_behalf_of','The account (if any) for which the funds of the invoice payment are intended. If set, the invoice will be presented with the branding and support information of the specified account. See the [Invoices with Connect](https://docs.stripe.com/billing/invoices/connect) documentation for details.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1882,30,'parent','parent','The parent that generated this invoice','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
