INSERT INTO "UI_DataItems" VALUES(1962,18,'receipt_url','receipt_url','This is the URL to view the receipt for this charge. The receipt is kept up-to-date to the latest state of the charge, including any refunds. If the charge is for an Invoice, the receipt will be stylized as an Invoice receipt.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1963,18,'refunded','refunded','Whether the charge has been fully refunded. If the charge is only partially refunded, this attribute will still be false.','BOOLEAN',5,20,NULL,1,0,NULL,NULL,'^(true|false|0|1)$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
