INSERT INTO "UI_DataItems" VALUES(1967,18,'source_transfer','source_transfer','The transfer ID which created this charge. Only present if the charge came from another Stripe account. [See the Connect documentation](https://docs.stripe.com/connect/destination-charges) for details.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1968,18,'statement_descriptor','statement_descriptor','For a non-card charge, text that appears on the customer''s statement as the statement descriptor. This value overrides the account''s default statement descriptor. For information about requirements, including the 22-character limit, see [the Statement Descriptor docs](https://docs.stripe.com/get-started/account/statement-descriptors).
INSERT INTO "UI_DataItems" VALUES(1969,18,'statement_descriptor_suffix','statement_descriptor_suffix','Provides information about a card charge. Concatenated to the account''s [statement descriptor prefix](https://docs.stripe.com/get-started/account/statement-descriptors#static) to form the complete statement descriptor that appears on the customer''s statement. If the account has no prefix value, the suffix is concatenated to the account''s statement descriptor.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1970,18,'status','status','The status of the payment is either `succeeded`, `pending`, or `failed`.','VARCHAR',255,1020,NULL,1,0,NULL,'["failed", "pending", "succeeded"]','one of: failed|pending|succeeded','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1971,18,'transfer','transfer','ID of the transfer to the `destination` account (only applicable if the charge was created using the `destination` parameter).','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1972,18,'transfer_data','transfer_data','An optional dictionary including the account to automatically transfer to as part of a destination charge. [See the Connect documentation](https://docs.stripe.com/connect/destination-charges) for details.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1973,18,'transfer_group','transfer_group','A string that identifies this transaction as part of a group. See the [Connect documentation](https://docs.stripe.com/connect/separate-charges-and-transfers#transfer-options) for details.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1974,71,'amount','amount','The amount (in cents (or local equivalent)) that transfers to your bank account or debit card.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1975,71,'application_fee','application_fee','The application fee (if any) for the payout. [See the Connect documentation](https://docs.stripe.com/connect/instant-payouts#monetization-and-fees) for details.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
