INSERT INTO "UI_DataItems" VALUES(1978,71,'automatic','automatic','Returns `true` if the payout is created by an [automated payout schedule](https://docs.stripe.com/payouts#payout-schedule) and `false` if it''s [requested manually](https://stripe.com/docs/payouts#manual-payouts).','BOOLEAN',5,20,NULL,1,0,NULL,NULL,'^(true|false|0|1)$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1979,71,'balance_transaction','balance_transaction','ID of the balance transaction that describes the impact of this payout on your account balance.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1980,71,'created','created','Time at which the object was created. Measured in seconds since the Unix epoch.','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1981,71,'currency','currency','Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).','VARCHAR',255,1020,NULL,1,0,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
