INSERT INTO "UI_DataItems" VALUES(1985,71,'failure_code','failure_code','Error code that provides a reason for a payout failure, if available. View our [list of failure codes](https://docs.stripe.com/api#payout_failures).','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
