INSERT INTO "UI_DataItems" VALUES(1987,71,'id','id','Unique identifier for the object.','VARCHAR',5000,20000,NULL,1,0,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1988,71,'livemode','livemode','If the object exists in live mode, the value is `true`. If the object exists in test mode, the value is `false`.','BOOLEAN',5,20,NULL,1,0,NULL,NULL,'^(true|false|0|1)$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1989,71,'metadata','metadata','Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format.','OBJECT',4000,16000,NULL,0,1,NULL,NULL,'maxlength: 4000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1990,71,'method','method','The method used to send this payout, which can be `standard` or `instant`. `instant` is supported for payouts to debit cards and bank accounts in certain countries. Learn more about [bank support for Instant Payouts](https://stripe.com/docs/payouts/instant-payouts-banks).','VARCHAR',5000,20000,NULL,1,0,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1991,71,'object','object','String representing the object''s type. Objects of the same type share the same value.','VARCHAR',255,1020,NULL,1,0,NULL,'["payout"]','one of: payout','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
