INSERT INTO "UI_DataItems" VALUES(1994,71,'reconciliation_status','reconciliation_status','If `completed`, you can use the [Balance Transactions API](https://docs.stripe.com/api/balance_transactions/list#balance_transaction_list-payout) to list all balance transactions that are paid out in this payout.','VARCHAR',255,1020,NULL,1,0,NULL,'["completed", "in_progress", "not_applicable"]','one of: completed|in_progress|not_applicable','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1995,71,'reversed_by','reversed_by','If the payout reverses, this is the ID of the payout that reverses this payout.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1996,71,'source_type','source_type','The source balance this payout came from, which can be one of the following: `card`, `fpx`, or `bank_account`.','VARCHAR',5000,20000,NULL,1,0,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1997,71,'statement_descriptor','statement_descriptor','Extra information about a payout that displays on the user''s bank statement.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1998,71,'status','status','Current status of the payout: `paid`, `pending`, `in_transit`, `canceled` or `failed`. A payout is `pending` until it''s submitted to the bank, when it becomes `in_transit`. The status changes to `paid` if the transaction succeeds, or to `failed` or `canceled` (within 5 business days). Some payouts that fail might initially show as `paid`, then change to `failed`.','VARCHAR',5000,20000,NULL,1,0,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(1999,71,'trace_id','trace_id','A value that generates from the beneficiary''s bank that allows users to track payouts with their bank. Banks might call this a "reference number" or something similar.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2000,71,'type','type','Can be `bank_account` or `card`.','VARCHAR',255,1020,NULL,1,0,NULL,'["bank_account", "card"]','one of: bank_account|card','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2001,104,'amount','amount','Amount, in cents (or local equivalent).','INTEGER',11,44,NULL,1,0,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2002,104,'balance_transaction','balance_transaction','Balance transaction that describes the impact on your account balance.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
