INSERT INTO "UI_DataItems" VALUES(2005,104,'currency','currency','Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).','VARCHAR',255,1020,NULL,1,0,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2006,104,'description','description','An arbitrary string attached to the object. You can use this for displaying to users (available on non-card refunds only).','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
