INSERT INTO "UI_DataItems" VALUES(2009,104,'failure_reason','failure_reason','Provides the reason for the refund failure. Possible values are: `lost_or_stolen_card`, `expired_or_canceled_card`, `charge_for_pending_refund_disputed`, `insufficient_funds`, `declined`, `merchant_request`, or `unknown`.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2010,104,'id','id','Unique identifier for the object.','VARCHAR',5000,20000,NULL,1,0,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2011,104,'instructions_email','instructions_email','For payment methods without native refund support (for example, Konbini, PromptPay), provide an email address for the customer to receive refund instructions.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2012,104,'metadata','metadata','Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format.','OBJECT',4000,16000,NULL,0,1,NULL,NULL,'maxlength: 4000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2013,104,'next_action','next_action','Any additional action required to complete the refund, such as instructions to display to the customer.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
