INSERT INTO "UI_DataItems" VALUES(2015,104,'payment_intent','payment_intent','ID of the PaymentIntent that''s refunded.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2016,104,'pending_reason','pending_reason','Provides the reason for why the refund is pending. Possible values are: `processing`, `insufficient_funds`, or `charge_pending`.','VARCHAR',255,1020,NULL,0,1,NULL,'["charge_pending", "insufficient_funds", "processing"]','one of: charge_pending|insufficient_funds|processing','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2017,104,'presentment_details','presentment_details','Currency and amount of the refund as presented to the customer, when different from the settlement currency.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2018,104,'reason','reason','Reason for the refund, which is either user-provided (`duplicate`, `fraudulent`, or `requested_by_customer`) or generated by Stripe internally (`expired_uncaptured_charge`).','VARCHAR',255,1020,NULL,0,1,NULL,'["duplicate", "expired_uncaptured_charge", "fraudulent", "requested_by_customer"]','one of: duplicate|expired_uncaptured_charge|fraudulent|requested_by_customer','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2019,104,'receipt_number','receipt_number','This is the transaction number that appears on email receipts sent for this refund.','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2020,104,'source_transfer_reversal','source_transfer_reversal','The transfer reversal that''s associated with the refund. Only present if the charge came from another Stripe account.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2021,104,'status','status','Status of the refund. This can be `pending`, `requires_action`, `succeeded`, `failed`, or `canceled`. Learn more about [failed refunds](https://docs.stripe.com/refunds#failed-refunds).','VARCHAR',5000,20000,NULL,0,1,NULL,NULL,'maxlength: 5000','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2022,104,'transfer_reversal','transfer_reversal','This refers to the transfer reversal object if the accompanying transfer reverses. This is only applicable if the charge was created using the destination parameter.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2023,70,'amount','amount','Amount intended to be collected by this PaymentIntent. A positive integer representing how much to charge in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal) (e.g., 100 cents to charge $1.00 or 100 to charge ¥100, a zero-decimal currency). The minimum amount is $0.50 US or [equivalent in charge currency](https://docs.stripe.com/currencies#minimum-and-maximum-charge-amounts). The amount value supports up to eight digits (e.g., a value of 99999999 for a USD charge of $999,999.99).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2024,70,'amount_capturable','amount_capturable','Amount that can be captured from this PaymentIntent.','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2025,70,'amount_details','amount_details','Breakdown of the payment amount into components such as tip, where supported.','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2026,70,'amount_received','amount_received','Amount that this PaymentIntent collects.','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
