INSERT INTO "UI_DataItems" VALUES(2028,70,'application_fee_amount','application_fee_amount','The amount of the application fee (if any) that will be requested to be applied to the payment and transferred to the application owner''s Stripe account. The amount of the application fee collected will be capped at the total amount captured. For more information, see the PaymentIntents [use case for connected accounts](https://docs.stripe.com/payments/connected-accounts).','INTEGER',11,44,NULL,0,1,NULL,NULL,'^-?\d+$','stripe/openapi spec3','2026-06-28 06:03:06','2026-06-28 06:03:06');
