INSERT INTO "UI_DataItems" VALUES(2303,55,'same_as','sameAs','URL of a reference Web page that unambiguously indicates the item''s identity. E.g. the URL of the item''s Wikipedia page, Wikidata entry, or official website.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2304,55,'seller','seller','An entity which offers (sells / leases / lends / loans) the services / goods. A seller may also be a provider. (references Organization, Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2305,55,'serial_number','serialNumber','The serial number or any alphanumeric identifier of a particular product. When attached to an offer, it is a shortcut for the serial number of the product included in the offer.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2306,55,'shipping_details','shippingDetails','Indicates information about the shipping policies and options associated with an [[Offer]]. (references OfferShippingDetails)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
