INSERT INTO "UI_DataItems" VALUES(2340,60,'additional_type','additionalType','An additional type for the item, typically used for adding more specific types from external vocabularies in microdata syntax. This is a relationship between something and a class that the thing is in. Typically the value is a URI-identified RDF class, and in this case corresponds to the use of rdf:type in RDF. Text values can be used sparingly, for cases where useful information can be added without their being an appropriate schema to reference. In the case of text values, the class label should follow the schema.org style guide.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
