INSERT INTO "UI_DataItems" VALUES(2357,60,'diversity_policy','diversityPolicy','Statement on diversity policy by an [[Organization]] e.g. a [[NewsMediaOrganization]]. For a [[NewsMediaOrganization]], a statement describing the newsroom’s diversity policy on both staffing and sources, typically providing staffing data.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2358,60,'diversity_staffing_report','diversityStaffingReport','For an [[Organization]] (often but not necessarily a [[NewsMediaOrganization]]), a report on staffing diversity issues. In a news context this might be for example ASNE or RTDNA (US) reports, or self-reported.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2359,60,'duns','duns','The Dun & Bradstreet DUNS number for identifying an organization or business person.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2360,60,'email','email','Email address.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2361,60,'employee','employee','Someone working for this organization. (references Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2362,60,'employees','employees','People working for this organization. (references Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2363,60,'ethics_policy','ethicsPolicy','Statement about ethics policy, e.g. of a [[NewsMediaOrganization]] regarding journalistic and publishing practices, or of a [[Restaurant]], a page describing food source policies. In the case of a [[NewsMediaOrganization]], an ethicsPolicy is typically a statement describing the personal, organizational, and corporate standards of behavior expected by the organization.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2364,60,'event','event','Upcoming or past event associated with this place, organization, or action. (references Event)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2365,60,'events','events','Upcoming or past events associated with this place or organization. (references Event)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2366,60,'fax_number','faxNumber','The fax number.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2367,60,'founder','founder','A person or organization who founded this organization. (references Organization, Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2368,60,'founders','founders','A person who founded this organization. (references Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2369,60,'founding_date','foundingDate','The date that this organization was founded.','DATE',10,40,NULL,0,1,NULL,NULL,'^\d{4}-\d{2}-\d{2}$','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2370,60,'founding_location','foundingLocation','The place where the Organization was founded. (references Place)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2371,60,'funder','funder','A person or organization that supports (sponsors) something through some kind of financial contribution. (references Organization, Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2372,60,'funding','funding','A [[Grant]] that directly or indirectly provide funding or sponsorship for this item. See also [[ownershipFundingInfo]]. (references Grant)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2373,60,'global_location_number','globalLocationNumber','The [Global Location Number](http://www.gs1.org/gln) (GLN, sometimes also referred to as International Location Number or ILN) of the respective organization, person, or place. The GLN is a 13-digit number used to identify parties and physical locations.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2374,60,'has_certification','hasCertification','Certification information about a product, organization, service, place, or person. (references Certification)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2375,60,'has_credential','hasCredential','A credential awarded to the Person or Organization. (references Credential)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2376,60,'has_gs1_digital_link','hasGS1DigitalLink','The GS1 digital link associated with the object. This URL should conform to the particular requirements of digital links. The link should only contain the Application Identifiers (AIs) that are relevant for the entity being annotated, for instance a [[Product]] or an [[Organization]], and for the correct granularity. In particular, for products:A Digital Link that contains a serial number (AI 21) should only be present on instances of [[IndividualProduct]]A Digital Link that contains a lot number (AI 10) should be annotated as [[SomeProducts]] if only products from that lot are sold, or [[IndividualProduct]] if there is only a specific product.A Digital Link that contains a global model number (AI 8013) should be attached to a [[Product]] or a [[ProductModel]]. Other item types should be adapted similarly.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2377,60,'has_member_program','hasMemberProgram','MemberProgram offered by an Organization, for example an eCommerce merchant or an airline. (references MemberProgram)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2378,60,'has_merchant_return_policy','hasMerchantReturnPolicy','Specifies a MerchantReturnPolicy that may be applicable. (references MerchantReturnPolicy)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2379,60,'has_offer_catalog','hasOfferCatalog','Indicates an OfferCatalog listing for this Organization, Person, or Service. (references OfferCatalog)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2380,60,'has_pos','hasPOS','Points-of-Sales operated by the organization or person. (references Place)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2381,60,'has_shipping_service','hasShippingService','Specification of a shipping service offered by the organization. (references ShippingService)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2382,60,'image','image','An image of the item. This can be a [[URL]] or a fully described [[ImageObject]].','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2383,60,'interaction_statistic','interactionStatistic','The number of interactions for the CreativeWork using the WebSite or SoftwareApplication. The most specific child type of InteractionCounter should be used. (references InteractionCounter)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2384,60,'isic_v4','isicV4','The International Standard of Industrial Classification of All Economic Activities (ISIC), Revision 4 code for a particular organization, business person, or place.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2385,60,'iso6523_code','iso6523Code','An organization identifier as defined in [ISO 6523(-1)](https://en.wikipedia.org/wiki/ISO/IEC_6523). The identifier should be in the `XXXX:YYYYYY:ZZZ` or `XXXX:YYYYYY`format. Where `XXXX` is a 4 digit _ICD_ (International Code Designator), `YYYYYY` is an _OID_ (Organization Identifier) with all formatting characters (dots, dashes, spaces) removed with a maximal length of 35 characters, and `ZZZ` is an optional OPI (Organization Part Identifier) with a maximum length of 35 characters. The various components (ICD, OID, OPI) are joined with a colon character (ASCII `0x3a`). Note that many existing organization identifiers defined as attributes like [leiCode](https://schema.org/leiCode) (`0199`), [duns](https://schema.org/duns) (`0060`) or [GLN](https://schema.org/globalLocationNumber) (`0088`) can be expressed using ISO-6523. If possible, ISO-6523 codes should be preferred to populating [vatID](https://schema.org/vatID) or [taxID](https://schema.org/taxID), as ISO identifiers are less ambiguous.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2386,60,'keywords','keywords','Keywords or tags used to describe some item. Multiple textual entries in a keywords list are typically delimited by commas, or by repeating the property.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2387,60,'knows_about','knowsAbout','Of a [[Person]], and less typically of an [[Organization]], to indicate a topic that is known about - suggesting possible expertise but not implying it. We do not distinguish skill levels here, or relate this to educational content, events, objectives or [[JobPosting]] descriptions.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2388,60,'knows_language','knowsLanguage','Of a [[Person]], and less typically of an [[Organization]], to indicate a known language. We do not distinguish skill levels or reading/writing/speaking/signing here. Use language codes from the [IETF BCP 47 standard](http://tools.ietf.org/html/bcp47).','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2389,60,'legal_address','legalAddress','The legal address of an organization which acts as the officially registered address used for legal and tax purposes. The legal address can be different from the place of operations of a business and other addresses can be part of an organization. (references PostalAddress)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2390,60,'legal_name','legalName','The official name of the organization, e.g. the registered company name.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2391,60,'legal_representative','legalRepresentative','One or multiple persons who represent this organization legally such as CEO or sole administrator. (references Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2392,60,'lei_code','leiCode','An organization identifier that uniquely identifies a legal entity as defined in ISO 17442.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2393,60,'location','location','The location of, for example, where an event is happening, where an organization is located, or where an action takes place.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2394,60,'logo','logo','An associated logo.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2395,60,'main_entity_of_page','mainEntityOfPage','Indicates a page (or other CreativeWork) for which this thing is the main entity being described. See [background notes](/docs/datamodel.html#mainEntityBackground) for details.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2396,60,'makes_offer','makesOffer','A pointer to products or services offered by the organization or person. (references Offer)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2397,60,'member','member','A member of an Organization or a ProgramMembership. Organizations can be members of organizations; ProgramMembership is typically for individuals. (references Organization, Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2398,60,'member_of','memberOf','An Organization (or ProgramMembership) to which this Person or Organization belongs. (references MemberProgramTier, Organization, ProgramMembership)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2399,60,'members','members','A member of this organization. (references Organization, Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2400,60,'naics','naics','The North American Industry Classification System (NAICS) code for a particular organization or business person.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2401,60,'nonprofit_status','nonprofitStatus','nonprofitStatus indicates the legal status of a non-profit organization in its primary place of business. (enumeration NonprofitType)','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2402,60,'number_of_employees','numberOfEmployees','The number of employees in an organization, e.g. business. (references QuantitativeValue)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2403,60,'owner','owner','A person or organization who owns this Thing. (references Organization, Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2404,60,'ownership_funding_info','ownershipFundingInfo','For an [[Organization]] (often but not necessarily a [[NewsMediaOrganization]]), a description of organizational ownership structure; funding and grants. In a news/media setting, this is with particular reference to editorial independence. Note that the [[funder]] is also available and can be used to make basic funder information machine-readable.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2405,60,'owns','owns','Things owned by the organization or person. (references Thing)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2406,60,'parent_organization','parentOrganization','The larger organization that this organization is a [[subOrganization]] of, if any. (references Organization)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2407,60,'potential_action','potentialAction','Indicates a potential Action, which describes an idealized action in which this thing would play an ''object'' role. (references Action)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2408,60,'publishing_principles','publishingPrinciples','The publishingPrinciples property indicates (typically via [[URL]]) a document describing the editorial principles of an [[Organization]] (or individual, e.g. a [[Person]] writing a blog) that relate to their activities as a publisher, e.g. ethics or diversity policies. When applied to a [[CreativeWork]] (e.g. [[NewsArticle]]) the principles are those of the party primarily responsible for the creation of the [[CreativeWork]]. While such policies are most typically expressed in natural language, sometimes related information (e.g. indicating a [[funder]]) can be expressed using schema.org terminology.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2409,60,'review','review','A review of the item. (references Review)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2410,60,'reviews','reviews','Review of the item. (references Review)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2411,60,'same_as','sameAs','URL of a reference Web page that unambiguously indicates the item''s identity. E.g. the URL of the item''s Wikipedia page, Wikidata entry, or official website.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2412,60,'seeks','seeks','A pointer to products or services sought by the organization or person (demand). (references Demand)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2413,60,'service_area','serviceArea','The geographic area where the service is provided. (references AdministrativeArea, GeoShape, Place)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2414,60,'skills','skills','A statement of knowledge, skill, ability, task or any other assertion expressing a competency that is either claimed by a person, an organization or desired or required to fulfill a role or to work in an occupation.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2415,60,'slogan','slogan','A slogan or motto associated with the item.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2416,60,'sponsor','sponsor','A person or organization that supports a thing through a pledge, promise, or financial contribution. E.g. a sponsor of a Medical Study or a corporate sponsor of an event. (references Organization, Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2417,60,'sub_organization','subOrganization','A relationship between two organizations where the first includes the second, e.g., as a subsidiary. See also: the more specific ''department'' property. (references Organization)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2418,60,'subject_of','subjectOf','A CreativeWork or Event about this Thing. (references CreativeWork, Event)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2419,60,'tax_id','taxID','The Tax / Fiscal ID of the organization or person, e.g. the TIN in the US or the CIF/NIF in Spain.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2420,60,'telephone','telephone','The telephone number.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2421,60,'unnamed_sources_policy','unnamedSourcesPolicy','For an [[Organization]] (typically a [[NewsMediaOrganization]]), a statement about policy on use of unnamed sources and the decision process required.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2422,60,'url','url','URL of the item.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2423,60,'vat_id','vatID','The value-added Tax ID of the organization or person with national prefix (for example IT123456789). Can also be described as [[iso6523Code]] with proper prefix.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2424,72,'additional_name','additionalName','An additional name for a Person, can be used for a middle name.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2425,72,'additional_type','additionalType','An additional type for the item, typically used for adding more specific types from external vocabularies in microdata syntax. This is a relationship between something and a class that the thing is in. Typically the value is a URI-identified RDF class, and in this case corresponds to the use of rdf:type in RDF. Text values can be used sparingly, for cases where useful information can be added without their being an appropriate schema to reference. In the case of text values, the class label should follow the schema.org style guide.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2426,72,'address','address','Physical address of the item.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2427,72,'affiliation','affiliation','An organization that this person is affiliated with. For example, a school/university, a club, or a team. (references Organization)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2428,72,'agent_interaction_statistic','agentInteractionStatistic','The number of completed interactions for this entity, in a particular role (the ''agent''), in a particular action (indicated in the statistic), and in a particular context (i.e. interactionService). (references InteractionCounter)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2429,72,'alternate_name','alternateName','An alias for the item.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
