INSERT INTO "UI_DataItems" VALUES(2451,72,'funding','funding','A [[Grant]] that directly or indirectly provide funding or sponsorship for this item. See also [[ownershipFundingInfo]]. (references Grant)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2452,72,'gender','gender','Gender of something, typically a [[Person]], but possibly also fictional characters, animals, etc. While https://schema.org/Male and https://schema.org/Female may be used, text strings are also acceptable for people who are not a binary gender. The [[gender]] property can also be used in an extended sense to cover e.g. the gender of sports teams. As with the gender of individuals, we do not try to enumerate all possibilities. A mixed-gender [[SportsTeam]] can be indicated with a text value of "Mixed".','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2453,72,'given_name','givenName','Given name. In the U.S., the first name of a Person.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2454,72,'global_location_number','globalLocationNumber','The [Global Location Number](http://www.gs1.org/gln) (GLN, sometimes also referred to as International Location Number or ILN) of the respective organization, person, or place. The GLN is a 13-digit number used to identify parties and physical locations.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
