INSERT INTO "UI_DataItems" VALUES(2483,72,'parents','parents','A parents of the person. (references Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2484,72,'performer_in','performerIn','Event that this person is a performer or participant in. (references Event)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2485,72,'potential_action','potentialAction','Indicates a potential Action, which describes an idealized action in which this thing would play an ''object'' role. (references Action)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2486,72,'pronouns','pronouns','A short string listing or describing pronouns for a person. Typically the person concerned is the best authority as pronouns are a critical part of personal identity and expression. Publishers and consumers of this information are reminded to treat this data responsibly, take country-specific laws related to gender expression into account, and be wary of out-of-date data and drawing unwarranted inferences about the person being described. In English, formulations such as "they/them", "she/her", and "he/him" are commonly used online and can also be used here. We do not intend to enumerate all possible micro-syntaxes in all languages. More structured and well-defined external values for pronouns can be referenced using the [[StructuredValue]] or [[DefinedTerm]] values.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2487,72,'publishing_principles','publishingPrinciples','The publishingPrinciples property indicates (typically via [[URL]]) a document describing the editorial principles of an [[Organization]] (or individual, e.g. a [[Person]] writing a blog) that relate to their activities as a publisher, e.g. ethics or diversity policies. When applied to a [[CreativeWork]] (e.g. [[NewsArticle]]) the principles are those of the party primarily responsible for the creation of the [[CreativeWork]]. While such policies are most typically expressed in natural language, sometimes related information (e.g. indicating a [[funder]]) can be expressed using schema.org terminology.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2488,72,'related_to','relatedTo','The most generic familial relation. (references Person)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2489,72,'same_as','sameAs','URL of a reference Web page that unambiguously indicates the item''s identity. E.g. the URL of the item''s Wikipedia page, Wikidata entry, or official website.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
INSERT INTO "UI_DataItems" VALUES(2490,72,'seeks','seeks','A pointer to products or services sought by the organization or person (demand). (references Demand)','RELATION',64,256,NULL,0,1,NULL,NULL,'key reference','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
