INSERT INTO "UI_DataItems" VALUES(2497,72,'tax_id','taxID','The Tax / Fiscal ID of the organization or person, e.g. the TIN in the US or the CIF/NIF in Spain.','VARCHAR',255,1020,NULL,0,1,NULL,NULL,'maxlength: 255','schemaorg-current-https','2026-06-28 06:03:06','2026-06-28 06:03:06');
